const item = $input.first().json;
const { run_id, company_name, company_domain, crawl_data, search_results } = item;

const systemPrompt = `You are an expert entity extraction AI. Extract structured company intelligence from the provided data. Return ONLY valid JSON.`;

const userPrompt = `Extract structured entities from this company data.

Company Name: ${company_name || 'Unknown'}
Domain: ${company_domain || 'Unknown'}

## Crawled Data
${(crawl_data || 'N/A').substring(0, 80000)}

## Search Results
${(search_results || 'N/A').substring(0, 40000)}

Required JSON structure:
{
  "company": { "name": "string", "domain": "string", "description": "string", "industry": "string", "founded_year": number|null, "headquarters": "string" },
  "products": [{ "name": "string", "description": "string", "category": "string" }],
  "technologies": ["string"],
  "key_people": [{ "name": "string", "role": "string", "linkedin": "string" }],
  "financials": { "total_funding": number|null, "latest_round": "string", "investors": ["string"] },
  "competitors": ["string"],
  "confidence_scores": { "overall": 0.0, "data_quality": 0.0, "source_reliability": 0.0 }
}`;

const fullPrompt = `${systemPrompt}\n\n${userPrompt}`;
const estimatedTokens = Math.ceil(fullPrompt.length / 3.5);
const processingStart = Date.now();

return [{
  json: {
    run_id,
    company_name,
    company_domain,
    systemPrompt,
    userPrompt,
    prompt: fullPrompt,
    estimatedTokens,
    processingStart,
    modelChoice: estimatedTokens > 100000 ? 'mimo' : 'deepseek'
  }
}];

const item = $input.first().json;

let modelUsed = 'unknown';
try {
  const deNode = $node['DeepSeek Error?'];
  if (deNode && deNode.json && deNode.json.choices && deNode.json.choices.length > 0) {
    modelUsed = 'deepseek-v4-flash';
  } else {
    modelUsed = 'mimo-v2.5';
  }
} catch (e) {
  modelUsed = 'mimo-v2.5';
}

const aiResponse = item.choices?.[0]?.message?.content || item.response || JSON.stringify(item);

let parsedData = null;
let parseSuccess = false;
let parseError = null;

if (item.error) {
  const prepNode = $node['Prepare Prompt'];
  return [{
    json: {
      ...item,
      parsedData: null,
      parseSuccess: false,
      parseError: item.error.message || 'API call failed',
      modelUsed,
      run_id: prepNode.json.run_id,
      company_domain: prepNode.json.company_domain
    }
  }];
}

try {
  let jsonStr = aiResponse;
  const jsonMatch = aiResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    jsonStr = jsonMatch[1];
  }
  parsedData = JSON.parse(jsonStr.trim());
  parseSuccess = true;
} catch (e) {
  parseError = e.message;
}

return [{
  json: {
    ...item,
    parsedData,
    parseSuccess,
    parseError,
    modelUsed,
    rawResponse: parseSuccess ? undefined : aiResponse
  }
}];

const item = $input.first().json;
const data = item.parsedData;
const errors = [];

if (!data || typeof data !== 'object') {
  return [{ json: { ...item, schemaValid: false, schemaErrors: ['parsedData is not an object'], validationDetail: 'No valid data to validate' } }];
}

if (!data.company) errors.push('Missing top-level "company" object');
else {
  if (!data.company.name) errors.push('Missing company.name');
  if (!data.company.domain) errors.push('Missing company.domain');
}

if (data.products !== undefined && !Array.isArray(data.products)) errors.push('"products" must be an array');
if (data.technologies !== undefined && !Array.isArray(data.technologies)) errors.push('"technologies" must be an array');
if (data.competitors !== undefined && !Array.isArray(data.competitors)) errors.push('"competitors" must be an array');

if (!data.confidence_scores || typeof data.confidence_scores !== 'object') {
  errors.push('Missing or invalid "confidence_scores" object');
} else {
  if (typeof data.confidence_scores.overall !== 'number') errors.push('confidence_scores.overall must be a number');
  if (typeof data.confidence_scores.data_quality !== 'number') data.confidence_scores.data_quality = data.confidence_scores.overall;
  if (typeof data.confidence_scores.source_reliability !== 'number') data.confidence_scores.source_reliability = data.confidence_scores.overall;
}

return [{ json: { ...item, schemaValid: errors.length === 0, schemaErrors: errors, validationDetail: errors.length > 0 ? 'Schema validation failed: ' + errors.join('; ') : 'Schema validation passed' } }];

