const item = $input.first().json;

let repairResponse = '';
if (item.error) {
  repairResponse = '{"error": "Repair API failed"}';
} else {
  repairResponse = item.choices?.[0]?.message?.content || item.response || '{}';
}

let parsedData = null;
let repairSuccess = false;

try {
  let jsonStr = repairResponse;
  const jsonMatch = repairResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1];
  parsedData = JSON.parse(jsonStr.trim());
  repairSuccess = true;
} catch (e) {
  parsedData = { repair_error: e.message, raw_preview: repairResponse.substring(0, 500) };
}

return [{ json: { ...item, parsedData, repairSuccess } }];
